/* Simple static dashboard for model analytics folders.
 *
 * Loads docs/manifest.json (generated by tools/build_manifest.py).
 */

const MANIFEST_URL = 'manifest.json';
const DATA_MANIFEST_URL = 'data/manifest.json';

const el = (id) => document.getElementById(id);

function setStatus(msg, isError = false) {
  const s = el('status');
  s.textContent = msg;
  s.style.color = isError ? '#ff8a8a' : '';
}

function basename(path) {
  const parts = path.split('/');
  return parts[parts.length - 1];
}

function prettyName(file) {
  return file
    .replace(/\.[^.]+$/, '')
    .replace(/_/g, ' ')
    .trim();
}

function getPlotType(file) {
  const name = file.replace(/\.[^.]+$/, '');
  if (name.startsWith('overall_')) return 'overall';
  if (name.startsWith('global_')) return 'global';
  if (name.startsWith('acc_vs_temp_')) return 'accuracy vs temperature';
  if (name.startsWith('legend_')) return 'legend';
  return 'other';
}

function escapeHtml(s) {
  return String(s)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#039;');
}

function parseCsv(text) {
  const rows = [];
  let row = [];
  let field = '';
  let inQuotes = false;

  for (let i = 0; i < text.length; i++) {
    const c = text[i];

    if (inQuotes) {
      if (c === '"') {
        const next = text[i + 1];
        if (next === '"') {
          field += '"';
          i++;
        } else {
          inQuotes = false;
        }
      } else {
        field += c;
      }
      continue;
    }

    if (c === '"') {
      inQuotes = true;
      continue;
    }

    if (c === ',') {
      row.push(field);
      field = '';
      continue;
    }

    if (c === '\n') {
      row.push(field);
      field = '';
      rows.push(row);
      row = [];
      continue;
    }

    if (c === '\r') continue;
    field += c;
  }

  if (field.length > 0 || row.length > 0) {
    row.push(field);
    rows.push(row);
  }

  if (rows.length && rows[rows.length - 1].length === 1 && rows[rows.length - 1][0] === '') {
    rows.pop();
  }

  return rows;
}

function renderTable(container, csvText, maxRows = 80) {
  if (!csvText || !csvText.trim()) {
    container.innerHTML = '<div class="muted">(empty)</div>';
    return;
  }

  const rows = parseCsv(csvText);
  if (!rows.length) {
    container.innerHTML = '<div class="muted">(no rows)</div>';
    return;
  }

  const head = rows[0];
  const body = rows.slice(1, maxRows + 1);

  let html = '<table><thead><tr>';
  for (const h of head) html += `<th>${escapeHtml(h)}</th>`;
  html += '</tr></thead><tbody>';

  for (const r of body) {
    html += '<tr>';
    for (let i = 0; i < head.length; i++) {
      const val = r[i] ?? '';
      html += `<td>${escapeHtml(val)}</td>`;
    }
    html += '</tr>';
  }

  html += '</tbody></table>';

  if (rows.length - 1 > maxRows) {
    html += `<div class="muted" style="padding:8px 10px;">Showing first ${maxRows} rows of ${rows.length - 1}.</div>`;
  }

  container.innerHTML = html;
}

async function safeFetchText(url) {
  try {
    const r = await fetch(url, { cache: 'no-store' });
    if (!r.ok) return null;
    return await r.text();
  } catch {
    return null;
  }
}

async function fetchTextWithFallback(urls) {
  for (const url of urls) {
    if (!url) continue;
    const txt = await safeFetchText(url);
    if (txt) return txt;
  }
  return null;
}

let manifest = null;

let llnManifest = null;

function getSelectedDataset() {
  const datasetId = el('llnDatasetSelect')?.value;
  return (llnManifest?.datasets || []).find((d) => d.id === datasetId) || null;
}

function getSelectedDatasetFile(dataset) {
  if (!dataset) return null;
  const path = el('llnFileSelect')?.value;
  return (dataset.files || []).find((f) => f.path === path) || null;
}

function renderLlnPreview(dataset, file) {
  const meta = el('llnMeta');
  const preview = el('llnPreview');
  if (!meta || !preview) return;

  if (!dataset || !file) {
    meta.textContent = 'No LLN dataset selected.';
    preview.innerHTML = '<div class="muted" style="padding:8px 10px;">(select a dataset file)</div>';
    return;
  }

  meta.textContent = `Showing ${dataset.label || dataset.id} — ${file.label}`;

  const directPath = file.path || '';
  const noLeadingSlash = directPath.replace(/^\/+/, '');
  const withoutDocsPrefix = noLeadingSlash.replace(/^docs\//, '');
  const withDocsPrefix = noLeadingSlash.startsWith('docs/') ? noLeadingSlash : `docs/${noLeadingSlash}`;

  fetchTextWithFallback([
    directPath,
    `./${noLeadingSlash}`,
    withoutDocsPrefix,
    `./${withoutDocsPrefix}`,
    withDocsPrefix,
    `./${withDocsPrefix}`,
  ]).then((txt) => {
    if (!txt) {
      preview.innerHTML = `<div class="muted" style="padding:8px 10px;">Could not load LLN CSV file: ${escapeHtml(file.path)}</div>`;
      return;
    }
    renderTable(preview, txt, 120);
  });
}

function populateLlnSelectors() {
  const datasetSel = el('llnDatasetSelect');
  const fileSel = el('llnFileSelect');
  const meta = el('llnMeta');
  const preview = el('llnPreview');

  if (!datasetSel || !fileSel || !meta || !preview) return;

  datasetSel.innerHTML = '';
  fileSel.innerHTML = '';

  const datasets = llnManifest?.datasets || [];
  if (!datasets.length) {
    datasetSel.innerHTML = '<option value="">(no LLN datasets)</option>';
    fileSel.innerHTML = '<option value="">(no files)</option>';
    meta.textContent = 'LLN dataset manifest not found.';
    preview.innerHTML = '<div class="muted" style="padding:8px 10px;">(missing data/manifest.json)</div>';
    return;
  }

  for (const d of datasets) {
    const opt = document.createElement('option');
    opt.value = d.id;
    opt.textContent = d.label || d.id;
    datasetSel.appendChild(opt);
  }

  function rebuildFiles() {
    const dataset = getSelectedDataset();
    fileSel.innerHTML = '';
    const files = dataset?.files || [];
    for (const f of files) {
      const opt = document.createElement('option');
      opt.value = f.path;
      opt.textContent = f.label || basename(f.path);
      fileSel.appendChild(opt);
    }
    if (files.length) fileSel.value = files[0].path;
    renderLlnPreview(dataset, getSelectedDatasetFile(dataset));
  }

  datasetSel.value = datasets[0].id;
  rebuildFiles();

  datasetSel.onchange = () => rebuildFiles();
  fileSel.onchange = () => {
    const dataset = getSelectedDataset();
    renderLlnPreview(dataset, getSelectedDatasetFile(dataset));
  };
}

async function loadLlnManifest() {
  try {
    const r = await fetch(DATA_MANIFEST_URL, { cache: 'no-store' });
    if (!r.ok) throw new Error(`HTTP ${r.status}`);
    llnManifest = await r.json();
  } catch {
    llnManifest = null;
  }
  populateLlnSelectors();
}


function getSelectedModel() {
  const modelId = el('modelSelect').value;
  return (manifest?.models || []).find((m) => m.id === modelId) || null;
}

function getSelectedAgg(model) {
  if (!model) return null;
  const aggId = el('aggSelect').value;
  return (model.aggs || []).find((a) => a.id === aggId) || null;
}

function clearMetrics() {
  el('metricsOverall').innerHTML = '';
  el('metricsGlobal').innerHTML = '';
  el('methodRankings').textContent = '';
  el('runConfig').textContent = '';
}

function renderSelectionSummary(model, agg) {
  const wrap = el('selectionSummary');
  if (!model || !agg) {
    wrap.innerHTML = '<span class="muted">No run selected.</span>';
    return;
  }

  const plotCount = (agg.plots || []).length;
  const fileCount = Object.keys(agg.files || {}).length;
  const topkCount = Object.keys(agg.histograms || {}).length;

  wrap.innerHTML = `
    <span class="pill"><strong>Model:</strong> ${escapeHtml(model.label || model.id)}</span>
    <span class="pill"><strong>Run:</strong> ${escapeHtml(agg.label || agg.id)}</span>
    <span class="pill">${plotCount} plot${plotCount === 1 ? '' : 's'}</span>
    <span class="pill">${fileCount} key file${fileCount === 1 ? '' : 's'}</span>
    <span class="pill">${topkCount} histogram group${topkCount === 1 ? '' : 's'}</span>
  `;
}

function renderDownloads(agg) {
  const wrap = el('downloads');
  wrap.innerHTML = '';
  if (!agg || !agg.files || Object.keys(agg.files).length === 0) {
    wrap.innerHTML = '<span class="muted">No files found.</span>';
    return;
  }

  const keys = Object.keys(agg.files).sort();
  for (const k of keys) {
    const href = agg.files[k];
    const a = document.createElement('a');
    a.href = href;
    a.target = '_blank';
    a.rel = 'noreferrer';
    a.className = 'chip';
    a.textContent = k;
    wrap.appendChild(a);
  }
}

function refreshPlotTypeOptions(agg) {
  const plots = (agg?.plots || []).slice();
  const types = [...new Set(plots.map((p) => getPlotType(basename(p))))].sort();
  const sel = el('plotTypeSelect');
  const current = sel.value;

  sel.innerHTML = '';
  const allOpt = document.createElement('option');
  allOpt.value = 'all';
  allOpt.textContent = 'all plot types';
  sel.appendChild(allOpt);

  for (const t of types) {
    const opt = document.createElement('option');
    opt.value = t;
    opt.textContent = t;
    sel.appendChild(opt);
  }

  sel.value = types.includes(current) ? current : 'all';
}

function renderPlots(agg) {
  const gallery = el('plots');
  const empty = el('plotsEmpty');
  gallery.innerHTML = '';
  empty.textContent = '';

  const selectedType = el('plotTypeSelect').value || 'all';
  const plots = (agg?.plots || []).filter((p) => {
    if (selectedType === 'all') return true;
    return getPlotType(basename(p)) === selectedType;
  });

  if (!plots.length) {
    empty.textContent = 'No matching plots for this filter.';
    return;
  }

  for (const p of plots) {
    const div = document.createElement('div');
    div.className = 'thumb';

    const link = document.createElement('a');
    link.href = p;
    link.target = '_blank';
    link.rel = 'noreferrer';

    const img = document.createElement('img');
    img.loading = 'lazy';
    img.src = p;
    img.alt = basename(p);

    link.appendChild(img);

    const cap = document.createElement('div');
    cap.className = 'cap';
    cap.textContent = prettyName(basename(p));

    div.appendChild(link);
    div.appendChild(cap);
    gallery.appendChild(div);
  }
}

async function renderMetrics(agg) {
  clearMetrics();
  if (!agg) return;

  const overallPath = agg.files?.['metrics_overall.csv'];
  const globalPath = agg.files?.['metrics_global.csv'];

  if (overallPath) {
    const txt = await safeFetchText(overallPath);
    if (txt) renderTable(el('metricsOverall'), txt, 80);
    else el('metricsOverall').innerHTML = '<div class="muted">Could not load.</div>';
  } else {
    el('metricsOverall').innerHTML = '<div class="muted">(missing)</div>';
  }

  if (globalPath) {
    const txt = await safeFetchText(globalPath);
    if (txt) renderTable(el('metricsGlobal'), txt, 80);
    else el('metricsGlobal').innerHTML = '<div class="muted">Could not load.</div>';
  } else {
    el('metricsGlobal').innerHTML = '<div class="muted">(missing)</div>';
  }

  const rankingsPath = agg.files?.['method_rankings.txt'];
  if (rankingsPath) {
    const txt = await safeFetchText(rankingsPath);
    el('methodRankings').textContent = txt ?? '(could not load)';
  } else {
    el('methodRankings').textContent = '(missing)';
  }

  const configPath = agg.files?.['run_config.json'];
  if (configPath) {
    const txt = await safeFetchText(configPath);
    el('runConfig').textContent = txt ?? '(could not load)';
  } else {
    el('runConfig').textContent = '(missing)';
  }
}

let histState = {
  topk: null,
  kind: null,
  temp: null,
  q: 0,
  minQ: 0,
  maxQ: 0,
  ext: 'png',
};

function _setOptions(selectEl, items, placeholder = '(none)') {
  selectEl.innerHTML = '';
  if (!items.length) {
    const opt = document.createElement('option');
    opt.value = '';
    opt.textContent = placeholder;
    selectEl.appendChild(opt);
    return;
  }

  for (const it of items) {
    const opt = document.createElement('option');
    opt.value = it;
    opt.textContent = it;
    selectEl.appendChild(opt);
  }
}

function refreshHistogramControls(agg) {
  const hist = agg?.histograms || {};

  const topks = Object.keys(hist).sort();
  _setOptions(el('histTopk'), topks, '(no histograms)');

  histState.topk = topks[0] || null;
  el('histTopk').value = histState.topk || '';

  const kinds = histState.topk ? Object.keys(hist[histState.topk] || {}).sort() : [];
  _setOptions(el('histKind'), kinds, '(none)');

  histState.kind = kinds[0] || null;
  el('histKind').value = histState.kind || '';

  const temps = (histState.topk && histState.kind)
    ? Object.keys((hist[histState.topk] || {})[histState.kind] || {}).sort()
    : [];
  _setOptions(el('histTemp'), temps, '(none)');

  histState.temp = temps[0] || null;
  el('histTemp').value = histState.temp || '';

  syncHistogramRange(agg);
  updateHistogramImage(agg);
}

function syncHistogramRange(agg) {
  const hist = agg?.histograms || {};
  const info = (histState.topk && histState.kind && histState.temp)
    ? (((hist[histState.topk] || {})[histState.kind] || {})[histState.temp] || null)
    : null;

  if (!info) {
    histState.minQ = 0;
    histState.maxQ = 0;
    histState.ext = 'png';
    return;
  }

  histState.minQ = Number(info.min_q ?? 0);
  histState.maxQ = Number(info.max_q ?? 0);
  histState.ext = info.ext || 'png';

  const qEl = el('histQ');
  let q = Number(qEl.value || 0);
  if (Number.isNaN(q)) q = histState.minQ;
  q = Math.max(histState.minQ, Math.min(histState.maxQ, q));
  qEl.value = String(q);
  histState.q = q;

  el('histRange').textContent = info
    ? `q range: ${histState.minQ}..${histState.maxQ}`
    : '';
}

function updateHistogramImage(agg) {
  const empty = el('histEmpty');
  const img = el('histImg');
  const link = el('histLink');

  empty.textContent = '';

  if (!agg || !histState.topk || !histState.kind || !histState.temp) {
    img.style.display = 'none';
    link.href = '#';
    empty.textContent = 'No histograms available.';
    return;
  }

  const q = Number(el('histQ').value || 0);
  histState.q = q;

  const path = `${agg.base_path}/histograms/${histState.topk}/${histState.kind}/${histState.temp}/q_${q}.${histState.ext}`;

  img.style.display = 'block';
  img.src = path;
  img.alt = `q_${q}.${histState.ext}`;
  link.href = path;

  img.onerror = () => {
    img.style.display = 'none';
    empty.textContent = `Missing image: q_${q}.${histState.ext}`;
  };
}

function hookHistogramEvents() {
  el('histTopk').addEventListener('change', () => {
    const model = getSelectedModel();
    const agg = getSelectedAgg(model);
    histState.topk = el('histTopk').value;

    const hist = agg?.histograms || {};
    const kinds = histState.topk ? Object.keys(hist[histState.topk] || {}).sort() : [];
    _setOptions(el('histKind'), kinds, '(none)');
    histState.kind = kinds[0] || null;
    el('histKind').value = histState.kind || '';

    const temps = (histState.topk && histState.kind)
      ? Object.keys((hist[histState.topk] || {})[histState.kind] || {}).sort()
      : [];
    _setOptions(el('histTemp'), temps, '(none)');
    histState.temp = temps[0] || null;
    el('histTemp').value = histState.temp || '';

    syncHistogramRange(agg);
    updateHistogramImage(agg);
  });

  el('histKind').addEventListener('change', () => {
    const model = getSelectedModel();
    const agg = getSelectedAgg(model);
    histState.kind = el('histKind').value;

    const hist = agg?.histograms || {};
    const temps = (histState.topk && histState.kind)
      ? Object.keys((hist[histState.topk] || {})[histState.kind] || {}).sort()
      : [];
    _setOptions(el('histTemp'), temps, '(none)');
    histState.temp = temps[0] || null;
    el('histTemp').value = histState.temp || '';

    syncHistogramRange(agg);
    updateHistogramImage(agg);
  });

  el('histTemp').addEventListener('change', () => {
    const model = getSelectedModel();
    const agg = getSelectedAgg(model);
    histState.temp = el('histTemp').value;
    syncHistogramRange(agg);
    updateHistogramImage(agg);
  });

  el('histQ').addEventListener('change', () => {
    const model = getSelectedModel();
    const agg = getSelectedAgg(model);
    syncHistogramRange(agg);
    updateHistogramImage(agg);
  });

  el('prevQ').addEventListener('click', () => {
    const qEl = el('histQ');
    let q = Number(qEl.value || 0);
    q = Math.max(histState.minQ, q - 1);
    qEl.value = String(q);
    const model = getSelectedModel();
    const agg = getSelectedAgg(model);
    updateHistogramImage(agg);
  });

  el('nextQ').addEventListener('click', () => {
    const qEl = el('histQ');
    let q = Number(qEl.value || 0);
    q = Math.min(histState.maxQ, q + 1);
    qEl.value = String(q);
    const model = getSelectedModel();
    const agg = getSelectedAgg(model);
    updateHistogramImage(agg);
  });
}

function populateSelectors() {
  const modelSel = el('modelSelect');
  const aggSel = el('aggSelect');

  const prevModel = modelSel.value;
  const prevAgg = aggSel.value;

  modelSel.innerHTML = '';
  aggSel.innerHTML = '';

  const models = manifest?.models || [];
  if (!models.length) {
    setStatus('No models found. Copy data into docs/models/<MODEL>/<RUN>/ and run tools/build_manifest.py', true);
    return;
  }

  for (const m of models) {
    const opt = document.createElement('option');
    opt.value = m.id;
    opt.textContent = m.label || m.id;
    modelSel.appendChild(opt);
  }

  modelSel.value = models.some((m) => m.id === prevModel) ? prevModel : models[0].id;

  function rebuildAggOptions() {
    const model = getSelectedModel();
    aggSel.innerHTML = '';

    const aggs = model?.aggs || [];
    for (const a of aggs) {
      const opt = document.createElement('option');
      opt.value = a.id;
      opt.textContent = a.label || a.id;
      aggSel.appendChild(opt);
    }

    if (aggs.length) {
      aggSel.value = aggs.some((a) => a.id === prevAgg) ? prevAgg : aggs[0].id;
    }
  }

  rebuildAggOptions();

  modelSel.onchange = async () => {
    rebuildAggOptions();
    await refreshView();
  };

  aggSel.onchange = async () => {
    await refreshView();
  };
}

async function refreshView() {
  const model = getSelectedModel();
  const agg = getSelectedAgg(model);

  if (!model || !agg) {
    setStatus('No data selected.', true);
    return;
  }

  setStatus(`Viewing ${model.id} / ${agg.id}`);

  renderSelectionSummary(model, agg);
  refreshPlotTypeOptions(agg);
  renderPlots(agg);
  renderDownloads(agg);
  refreshHistogramControls(agg);
  await renderMetrics(agg);
}

async function loadManifest() {
  setStatus('Loading manifest…');
  try {
    const r = await fetch(MANIFEST_URL, { cache: 'no-store' });
    if (!r.ok) throw new Error(`HTTP ${r.status}`);
    manifest = await r.json();

    const ts = manifest.generated_at ? new Date(manifest.generated_at).toLocaleString() : '';
    el('manifestMeta').textContent = ts ? `(manifest: ${ts})` : '';

    populateSelectors();
    await refreshView();
  } catch (e) {
    console.error(e);
    setStatus('Failed to load manifest.json. Did you run tools/build_manifest.py?', true);
  }
}

el('reloadBtn').addEventListener('click', async () => {
  await loadManifest();
  await loadLlnManifest();
});

el('plotTypeSelect').addEventListener('change', () => {
  const model = getSelectedModel();
  const agg = getSelectedAgg(model);
  renderPlots(agg);
});

hookHistogramEvents();
loadManifest();
loadLlnManifest();
